  "gold_actions": {
    "global": "Return [i * xs[i] for i in range(1, len(xs))] to produce the derivative coefficient list from the input polynomial coefficient list.",
    "subtasks": [
      {
        "subtask": "Map polynomial index to derivative coefficient via power rule",
        "atomics": [
          "Recognize xs as a 0-indexed list where position i encodes the x^i coefficient",
          "Derive the formula: output[i-1] = i * xs[i] for i in 1..len(xs)-1",
          "Confirm the output list has length len(xs)-1, with xs[0] dropped"
        ]
      },
      {
        "subtask": "Build the derivative coefficient list using a list comprehension",
        "atomics": [
          "Use range(1, len(xs)) to iterate over all non-constant term indices",
          "Multiply each index i by xs[i] to apply the power rule",
          "Return the collected list [i * xs[i] for i in range(1, len(xs))]"
        ]
      },
      {
        "subtask": "Validate implementation against provided doctests",
        "atomics": [
          "Trace derivative([3,1,2,4,5]): [1*1, 2*2, 3*4, 4*5] = [1, 4, 12, 20] — matches expected",
