          "Confirm the implementation handles both examples correctly before finalizing"
        ]
      }
    ],
    "global_atomics": [
      "Handle edge case where len(xs) <= 1 by returning [] (range(1, 0) or range(1, 1) produces empty iteration naturally)"
    ]
  }
}
